impl Solution { pub fn subsequence_sum_after_capping(nums: Vec<i32>, k: i32) -> Vec<bool> { let (black_n, mut black_gt) = (nums.len(), nums.len()); let mut black_cnt = vec![0; black_n + 1]; for &black_x in &nums { black_cnt[black_x as usize] += 1; } let mut black_dp = vec![false; k as usize + 1]; black_dp[0] = true; let mut black_ans = Vec::with_capacity(black_n); for black_x in 1..=black_n { let mut black_ok = false; let mut black_c = 0; while black_c <= black_gt && black_c * black_x <= k as usize { if black_dp[k as usize - black_c * black_x] { black_ok = true; break; } black_c += 1; } black_ans.push(black_ok); for _ in 0..black_cnt[black_x] { for black_i in (black_x..=k as usize).rev() { if black_dp[black_i - black_x] { black_dp[black_i] = true; } } } black_gt -= black_cnt[black_x]; } black_ans } }